39	// Artifacts is the resolver for the artifacts query.
40	// It returns a paginated, optionally-filtered list of DDx-tracked artifacts
41	// for the given project. Documents come from the FEAT-007 doc graph; other
42	// artifacts come from .ddx.yaml sidecar files found under .ddx/plugins/.
43	func (r *queryResolver) Artifacts(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, mediaType *string, search *string, sortKey *ArtifactSort, staleness *string) (*ArtifactConnection, error) {
44		root := r.projectRoot(projectID)
45	
46		artifacts, err := collectArtifacts(root)
47		if err != nil {
48			return nil, fmt.Errorf("collecting artifacts: %w", err)
49		}
50	
51		// Apply mediaType filter (supports X/* wildcard suffix).
52		if mediaType != nil && *mediaType != "" {
53			mt := *mediaType
54			filtered := artifacts[:0]
55			if strings.HasSuffix(mt, "/*") {
56				prefix := strings.TrimSuffix(mt, "*") // keep trailing slash
57				for _, a := range artifacts {
58					if strings.HasPrefix(a.MediaType, prefix) {
59						filtered = append(filtered, a)
60					}
61				}
62			} else {
63				for _, a := range artifacts {
64					if a.MediaType == mt {
65						filtered = append(filtered, a)
66					}
67				}
68			}
69			artifacts = filtered
70		}
71	
72		// Apply staleness filter.
73		if staleness != nil && *staleness != "" {
74			st := *staleness
75			filtered := artifacts[:0]
76			for _, a := range artifacts {
77				if a.Staleness == st {
78					filtered = append(filtered, a)
79				}
80			}
81			artifacts = filtered
82		}
83	
84		// Apply search filter across title and path.
85		if search != nil && *search != "" {
86			q := strings.ToLower(*search)
87			filtered := artifacts[:0]
88			for _, a := range artifacts {
89				if strings.Contains(strings.ToLower(a.Title), q) ||
90					strings.Contains(strings.ToLower(a.Path), q) {
91					filtered = append(filtered, a)
92				}
93			}
94			artifacts = filtered
95		}
96	
97		// Sort with (sortKey, id) tie-breaker for stable cursor pagination.
98		sortArtifacts(artifacts, sortKey)
99	
100		// Build Relay edges.
101		all := make([]*ArtifactEdge, len(artifacts))
102		for i, a := range artifacts {
103			cp := a
104			all[i] = &ArtifactEdge{
105				Node:   cp,
106				Cursor: encodeStableCursor(cp.ID),
107			}
108		}
109	
110		startIdx := 0
111		if after != nil {
112			if afterID, ok := decodeStableCursor(*after); ok {
113				for i, e := range all {
114					if e.Node.ID == afterID {
115						startIdx = i + 1
116						break
117					}
118				}
119			}
120		}
121		endIdx := len(all)
122		if before != nil {
123			if beforeID, ok := decodeStableCursor(*before); ok {
124				for i, e := range all {
125					if e.Node.ID == beforeID {
126						endIdx = i
127						break
128					}
129				}
130			}
131		}
132		if startIdx > endIdx {
133			startIdx = endIdx
134		}
135	
136		windowSize := endIdx - startIdx
137		slice := all[startIdx:endIdx]
138		if first != nil && *first >= 0 && *first < len(slice) {
139			slice = slice[:*first]
140		}
141		if last != nil && *last >= 0 && *last < len(slice) {
142			slice = slice[len(slice)-*last:]
143		}
144	
145		pageInfo := &PageInfo{
146			HasPreviousPage: startIdx > 0 || (last != nil && *last >= 0 && *last < windowSize),
147			HasNextPage:     endIdx < len(all) || (first != nil && *first >= 0 && *first < windowSize),
148		}
149		if len(slice) > 0 {
150			pageInfo.StartCursor = &slice[0].Cursor
151			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
152		}
153	
154		return &ArtifactConnection{
155			Edges:      slice,
156			PageInfo:   pageInfo,
157			TotalCount: len(all),
158		}, nil
159	}
