301	// collectSidecarArtifacts walks .ddx/plugins/ looking for *.ddx.yaml sidecar
302	// files, then builds an Artifact for each corresponding artifact file.
303	// Files whose sidecar is missing or unreadable are silently skipped.
304	func collectSidecarArtifacts(root string) ([]*Artifact, error) {
305		pluginsDir := filepath.Join(root, ".ddx", "plugins")
306		if _, err := os.Stat(pluginsDir); os.IsNotExist(err) {
307			return nil, nil
308		}
309	
310		var out []*Artifact
311		err := filepath.WalkDir(pluginsDir, func(path string, d fs.DirEntry, err error) error {
312			if err != nil || d.IsDir() {
313				return nil
314			}
315			if !strings.HasSuffix(path, ".ddx.yaml") {
316				return nil
317			}
318	
319			// Derive artifact path by stripping the .ddx.yaml suffix.
320			artifactPath := strings.TrimSuffix(path, ".ddx.yaml")
321	
322			// Parse the sidecar.
323			data, readErr := os.ReadFile(path)
324			if readErr != nil {
325				return nil // skip unreadable sidecars
326			}
327			var sidecar ddxSidecarFile
328			if yamlErr := yaml.Unmarshal(data, &sidecar); yamlErr != nil {
329				return nil // skip malformed sidecars
330			}
331	
332			rel, relErr := filepath.Rel(root, artifactPath)
333			if relErr != nil {
334				rel = artifactPath
335			}
336	
337			id := sidecar.DDx.ID
338			if id == "" {
339				id = "sidecar:" + rel
340			}
341	
342			title := sidecar.DDx.Title
343			if title == "" {
344				title = filepath.Base(artifactPath)
345			}
346	
347			mediaType := sidecar.DDx.MediaType
348			if mediaType == "" {
349				mediaType = "application/octet-stream"
350			}
351	
352			staleness := computeSidecarStaleness(artifactPath, sidecar.DDx.GeneratedBy)
353	
354			a := &Artifact{
355				ID:        id,
356				Path:      filepath.ToSlash(rel),
357				Title:     title,
358				MediaType: mediaType,
359				Staleness: staleness,
360			}
361	
362			if sidecar.DDx.Description != "" {
363				desc := sidecar.DDx.Description
364				a.Description = &desc
365			}
366	
367			if sidecar.DDx.GeneratedBy != nil {
368				gb := sidecar.DDx.GeneratedBy
369				sourceHashMatch := false
370				if gb.SourceHash != "" {
371					if hash, hashErr := fileSHA256(artifactPath); hashErr == nil {
372						sourceHashMatch = (hash == gb.SourceHash)
373					}
374				}
375				a.GeneratedBy = &ArtifactGeneratedBy{
376					RunID:           gb.RunID,
377					PromptSummary:   gb.PromptSummary,
378					SourceHashMatch: sourceHashMatch,
379				}
380			}
381	
382			// Populate ddxFrontmatter from the raw sidecar ddx block.
383			if fm, marshalErr := json.Marshal(sidecar.DDx); marshalErr == nil {
384				s := string(fm)
385				a.DdxFrontmatter = &s
386			}
387	
388			// Populate updatedAt from artifact file mod time.
389			if info, statErr := os.Stat(artifactPath); statErr == nil {
390				ts := info.ModTime().UTC().Format(time.RFC3339)
391				a.UpdatedAt = &ts
392			}
393	
394			out = append(out, a)
395			return nil
396		})
397		if err != nil {
398			return nil, err
399		}
400		return out, nil
401	}
